1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface QuoteStep {
7	  items: Item[];
8	}
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE = 0.1;
12	const CURSE_SURCHARGE = 0.5;
13	
14	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	const COMPONENT_TYPES = ["rune", "moonstone"];
22	const COMPONENT_PREMIUM = 25;
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	const isComponent = (item: Item): boolean =>
27	  COMPONENT_TYPES.includes(item.type);
28	
29	const isMainItem = (item: Item): boolean => !isComponent(item);
30	
31	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
32	// BLOCK_PREMIUM; any other count is priced per component.
33	const componentGroupBasePremium = (count: number): number =>
34	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
35	
36	// Item-specific surcharges are computed off each affected item's base premium.
37	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
38	const curseSurcharge = (item: Item): number =>
39	  item.cursed ? CURSE_SURCHARGE * basePremiumForItem(item) : 0;
40	
41	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
42	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
43	// that is only spuriously above a whole number.
44	const roundUpInMHPCOsFavor = (amount: number): number =>
45	  Math.ceil(Number(amount.toFixed(6)));
46	
47	const basePremiumForItem = (item: Item): number =>
48	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
49	
50	// Each main item is priced on its own.
51	const mainItemsBasePremium = (items: Item[]): number =>
52	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
53	
54	const countByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const item of items) {
57	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
58	  }
59	  return counts;
60	};
61	
62	// Components are grouped by type, and each group is block-priced.
63	const componentsBasePremium = (components: Item[]): number =>
64	  [...countByType(components).values()].reduce(
65	    (sum, count) => sum + componentGroupBasePremium(count),
66	    0,
67	  );
68	
69	export const quote = (
70	  customer: unknown,
71	  step: QuoteStep,
72	  quoteIndex: number,
73	): number => {
74	  const mainItems = step.items.filter(isMainItem);
75	  const components = step.items.filter(isComponent);
76	
77	  const policyBasePremium =
78	    mainItemsBasePremium(mainItems) + componentsBasePremium(components);
79	
80	  const itemSurcharges = step.items.reduce(
81	    (sum, item) => sum + curseSurcharge(item),
82	    0,
83	  );
84	  const firstInsuranceSurcharge = FIRST_INSURANCE_SURCHARGE * policyBasePremium;
85	
86	  const total =
87	    policyBasePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE;
88	  return roundUpInMHPCOsFavor(total);
89	};
