// Components are grouped by type, and each group is block-priced.
const componentsBasePremium = (components: Item[]): number =>
  [...countByType(components).values()].reduce(
    (sum, count) => sum + componentGroupBasePremium(count),
    0,
  );

const policyBasePremium = (items: Item[]): number =>
  mainItemsBasePremium(items.filter(isMainItem)) +
  componentsBasePremium(items.filter(isComponent));

// Tier 1 — item-specific surcharges: computed off each affected item's base
// premium and summed across the policy. (e.g. curse; later high-enchantment.)
const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + curseSurcharge(item), 0);

// Tier 2 — policy-wide modifiers: computed as a fraction of the policy base
// premium. (e.g. first-insurance surcharge; later loyalty/follow-up discounts.)
const policyWideModifiers = (policyBase: number): number =>
  FIRST_INSURANCE_SURCHARGE * policyBase;

export const quote = (
  customer: unknown,
  step: QuoteStep,
  quoteIndex: number,
): number => {
  const policyBase = policyBasePremium(step.items);

  const total =
    policyBase +
    itemSurcharges(step.items) +
    policyWideModifiers(policyBase) +
    PROCESSING_FEE;
  return roundUpInMHPCOsFavor(total);
};
